import * as Sentry from '@sentry/electron/main';
import { app } from 'electron';
import { logger } from '../logger';
import os from 'os';
import { getSentryDsn } from '../utils/runtime-config';

interface CrashContext {
  errorMessage: string;
  stackTrace?: string;
  userComment?: string;
  breadcrumbs?: Array<{ message: string; timestamp: Date; category?: string }>;
}

class CrashReportService {
  private initialized = false;
  private pendingCrash: CrashContext | null = null;

  /**
   * Initialize Sentry for crash reporting
   * NOTE: You need to set your Sentry DSN in environment variable SENTRY_DSN
   * or hardcode it here during development
   */
  initialize() {
    if (this.initialized) {
      logger.warn('CrashReportService already initialized');
      return;
    }

    // Get DSN from environment variable or runtime config
    // For production, it's loaded from runtime-config.json (generated at build time)
    // For development, it's loaded from .env file
    const dsn = getSentryDsn();

    logger.info('Attempting to initialize Sentry...', {
      dsnPresent: !!dsn,
      dsnLength: dsn?.length || 0,
    });

    if (!dsn) {
      logger.warn('SENTRY_DSN not set, crash reporting disabled');
      return;
    }

    try {
      Sentry.init({
        dsn,
        // Set environment based on build type
        environment: app.isPackaged ? 'production' : 'development',
        // Include app version for better tracking
        release: `server-compass@${app.getVersion()}`,
        // Only send crash reports when user explicitly submits them
        beforeSend: (event) => {
          // Return null to prevent automatic sending
          // We'll manually capture when user approves
          if (!this.pendingCrash) {
            return null;
          }
          return event;
        },
      });

      // Set user context with anonymous ID
      Sentry.setUser({
        id: this.getAnonymousUserId(),
      });

      // Set system context
      this.setSystemContext();

      this.initialized = true;
      logger.info('CrashReportService initialized successfully');
    } catch (error) {
      logger.error('Failed to initialize CrashReportService', error);
    }
  }

  /**
   * Add breadcrumb to track user actions
   */
  addBreadcrumb(message: string, category?: string, data?: Record<string, unknown>) {
    if (!this.initialized) return;

    Sentry.addBreadcrumb({
      message,
      category: category || 'user-action',
      level: 'info',
      timestamp: Date.now() / 1000,
      data,
    });
  }

  /**
   * Capture an error for potential reporting
   * This doesn't send it to Sentry yet, just stores it
   */
  captureError(error: Error, context?: Record<string, unknown>) {
    // Store crash info for potential user-initiated report
    this.pendingCrash = {
      errorMessage: error.message,
      stackTrace: error.stack,
    };

    if (!this.initialized) {
      logger.warn('Crash captured but Sentry not initialized - crash dialog will still work', error);
      return;
    }

    // Set additional context if Sentry is initialized
    if (context) {
      Sentry.setContext('crash_context', context);
    }

    logger.info('Crash captured, awaiting user decision to report', error);
  }

  /**
   * Submit the pending crash report with user comment
   */
  async submitCrashReport(userComment?: string): Promise<boolean> {
    if (!this.pendingCrash) {
      logger.error('Cannot submit crash report: No pending crash');
      return false;
    }

    if (!this.initialized) {
      logger.warn(
        'Cannot submit crash report: Sentry not initialized. Set SENTRY_DSN environment variable to enable crash reporting.'
      );
      // Clear the pending crash even though we can't send it
      this.pendingCrash = null;
      return false;
    }

    try {
      // Add user comment if provided
      if (userComment) {
        Sentry.setContext('user_feedback', {
          comment: userComment,
          timestamp: new Date().toISOString(),
        });
      }

      // Capture the exception
      const error = new Error(this.pendingCrash.errorMessage);
      if (this.pendingCrash.stackTrace) {
        error.stack = this.pendingCrash.stackTrace;
      }

      Sentry.captureException(error);

      // Flush events to ensure they're sent
      await Sentry.flush(2000);

      logger.info('Crash report submitted successfully');
      this.pendingCrash = null;
      return true;
    } catch (error) {
      logger.error('Failed to submit crash report', error);
      return false;
    }
  }

  /**
   * Dismiss the pending crash without reporting
   */
  dismissPendingCrash() {
    this.pendingCrash = null;
    logger.info('Pending crash report dismissed by user');
  }

  /**
   * Check if there's a pending crash awaiting user decision
   */
  hasPendingCrash(): boolean {
    return this.pendingCrash !== null;
  }

  /**
   * Get pending crash details for display in UI
   */
  getPendingCrash(): CrashContext | null {
    return this.pendingCrash;
  }

  /**
   * Generate or retrieve anonymous user ID for privacy
   */
  private getAnonymousUserId(): string {
    // Use machine ID or generate a random UUID
    // This helps correlate crashes from the same user without collecting PII
    const machineId = os.hostname() + os.platform();
    return Buffer.from(machineId).toString('base64').substring(0, 16);
  }

  /**
   * Set system information as context
   */
  private setSystemContext() {
    Sentry.setContext('system', {
      os: {
        name: os.platform(),
        version: os.release(),
        arch: os.arch(),
      },
      memory: {
        total: os.totalmem(),
        free: os.freemem(),
      },
      cpu: {
        cores: os.cpus().length,
        model: os.cpus()[0]?.model,
      },
      app: {
        version: app.getVersion(),
        name: app.getName(),
        isPackaged: app.isPackaged,
      },
    });
  }

  /**
   * Clean up on app shutdown
   */
  async shutdown() {
    if (this.initialized) {
      await Sentry.close(2000);
      logger.info('CrashReportService shut down');
    }
  }

}

export const crashReportService = new CrashReportService();
